/**
 * @param {number[]} nums
 * @param {number} k
 * @return {number}
 */
function solve(nums, k) {
    const N = nums.length;
    if (k === 0) {
        return 0;
    }

    // Maximum possible peaks in a cycle graph is floor(N/2).
    if (k > Math.floor(N / 2)) {
        return -1;
    }

    // 1. Precalculate Cost C_i for making nums[i] a peak
    const C = new Array(N);
    for (let i = 0; i < N; i++) {
        // Left neighbor index: (i - 1 + N) % N
        const L = nums[(i - 1 + N) % N];
        // Right neighbor index: (i + 1) % N
        const R = nums[(i + 1) % N];

        // Required value for nums[i] must be > max(L, R)
        const required_val = Math.max(L, R) + 1;

        // Cost = max(0, required_val - nums[i])
        const cost = Math.max(0, required_val - nums[i]);
        C[i] = cost;
    }

    const INF = 1e18;

    /**
     * Runs the linear DP considering elements 0 to N-1.
     * @param {number} startState0 - 0 if element 0 is NOT selected, 1 if element 0 IS selected.
     * @returns {number} The minimum cost for this case, or INF.
     */
    function runDP(startState0) {
        // DP[i][j][state]: Min cost considering 0..i, j peaks selected.
        // state=0: i is NOT a peak
        // state=1: i IS a peak

        // We use 1-based indexing for j (number of peaks)
        const DP = Array(N).fill(0).map(() => 
            Array(k + 1).fill(0).map(() => [INF, INF])
        );

        // Base Case: i = 0
        if (startState0 === 0) {
            // 0 is not selected
            DP[0][0][0] = 0;
        } else { // startState0 === 1
            // 0 is selected
            DP[0][1][1] = C[0];
        }

        // Iterate i from 1 to N-1
        for (let i = 1; i < N; i++) {
            for (let j = 0; j <= k; j++) {

                // --- State 0: i is NOT selected ---
                // Can come from i-1 being selected or not selected
                DP[i][j][0] = Math.min(DP[i-1][j][0], DP[i-1][j][1]);

                // --- State 1: i IS selected ---
                if (j >= 1) {
                    // Must come from i-1 NOT being selected
                    const prev_cost = DP[i-1][j-1][0];
                    if (prev_cost !== INF) {
                        DP[i][j][1] = prev_cost + C[i];
                    }
                }
            }
        }

        // The final result depends on how we constrain the end state N-1
        if (startState0 === 0) {
            // Case 1: 0 is NOT selected. N-1 can be selected or not.
            return Math.min(DP[N-1][k][0], DP[N-1][k][1]);
        } else {
            // Case 2: 0 IS selected. N-1 CANNOT be selected due to circular dependency.
            // We must take the cost where N-1 is NOT a peak.
            return DP[N-1][k][0];
        }
    }

    // Case 1: Assume element 0 is NOT a peak.
    let result1 = runDP(0);

    // Case 2: Assume element 0 IS a peak.
    let result2 = runDP(1);

    const min_cost = Math.min(result1, result2);

    return min_cost >= INF ? -1 : min_cost;
}
